final:
module ring_counter (
	input clk,
	input load,
	input [3:0] load_value,
	output reg [3:0] count);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (load)
		count <= load_value;
	else
		count <= {count[2:0], count[3]};
	end

endmodule
